fn solve(nums: Vec<i64>) -> i64 {
    // This problem is equivalent to finding the longest subsequence of nums
    // that is a permutation of [0, 1, 2, ..., k-1] for some k,
    // such that for the remaining elements, the k-th element maps to k-1.
    //
    // Let the remaining subsequence be s_0, s_1, ..., s_{k-1}.
    // We want s_i = i for all i in [0, k-1].
    //
    // This means we are looking for the longest sequence of indices i_0 < i_1 < ... < i_{k-1}
    // from the original array such that nums[i_j] = j for all j in [0, k-1].
    // This is a classic Longest Increasing Subsequence (LIS) variation, specifically a
    // variation solvable with a greedy approach or dynamic programming.
    //
    // Since the required values are strictly increasing (0, 1, 2, ...), a greedy approach works.
    // We try to match the smallest required value (0) first, then the next (1), and so on,
    // using the available elements in their original order.

    let mut target = 0;
    let mut count = 0;

    for &num in nums.iter() {
        // If the current element matches the next target value we are looking for,
        // we include it in our subsequence (effectively "keeping" it) and move to the next target.
        if num == target {
            count += 1;
            target += 1;
        }
        // If num != target, we discard this element (delete it) because it cannot be the next
        // required element in our target subsequence [0, 1, 2, ...].
    }

    count
}
